import type {
  ChartVariantInternal,
  TimeseriesBand,
} from './types/timeseries.js';
import type { ChartUnit } from '../../core/types/chart-unit.js';
import type { Timeseries } from '../../core/types/timeseries.js';
import { singleLineName } from '../../core/utils/single-line-name.js';
import type { XYChartData } from '../../xy-chart/types/xy-chart.js';

export interface TimeseriesPerShapeInput {
  line: Timeseries[];
  area: Timeseries[];
  bar: Timeseries[];
  band: TimeseriesBand[];
}

export type SeriesProps = {
  data: XYChartData[];
  unit: ChartUnit;
  seriesId: string;
};

export interface TransformTimeseriesDataResult {
  line: SeriesProps[];
  area: SeriesProps[];
  bar: SeriesProps[];
  band: SeriesProps[];
  units: Set<ChartUnit>;
}

const mapTimeseries = (series: Timeseries, seriesId: string): SeriesProps => {
  const { datapoints, name, unit, ...extraSeriesProps } = series;
  const seriesName = singleLineName(name);

  const data: XYChartData[] = datapoints.map((datapoint) => ({
    ...extraSeriesProps,
    start: datapoint.start,
    end: datapoint.end,
    center: datapoint.center,
    value: datapoint.value,
    seriesName,
    seriesId,
  }));

  return { data, unit, seriesId };
};

const mapBand = (band: TimeseriesBand, seriesId: string): SeriesProps => {
  const { datapoints, name, unit, ...extraSeriesProps } = band;
  const seriesName = singleLineName(name);

  const data: XYChartData[] = datapoints.map((datapoint) => ({
    ...extraSeriesProps,
    start: datapoint.start,
    end: datapoint.end,
    y0: datapoint.y0,
    y1: datapoint.y1,
    seriesName,
    seriesId,
  }));

  return { data, unit, seriesId };
};

export function transformTimeseriesDataToXYChart(
  input: TimeseriesPerShapeInput,
  shapeRenderOrder: ChartVariantInternal[],
): TransformTimeseriesDataResult {
  const units: Set<ChartUnit> = new Set();
  const result: TransformTimeseriesDataResult = {
    line: [],
    area: [],
    bar: [],
    band: [],
    units,
  };

  let globalIndex = 0;

  shapeRenderOrder.forEach((shape) => {
    if (shape === 'band') {
      input.band.forEach((band) => {
        const mapped = mapBand(band, `${shape}-${globalIndex}`);
        result.band.push(mapped);
        units.add(mapped.unit);
        globalIndex++;
      });
    } else {
      input[shape].forEach((series) => {
        const mapped = mapTimeseries(series, `${shape}-${globalIndex}`);
        result[shape].push(mapped);
        units.add(mapped.unit);
        globalIndex++;
      });
    }
  });

  return result;
}
